// 注意这里的类名，要和主文件里 YFJ_Module_ + ucfirst('bazi_cesuan') 对应
class YFJ_Module_Liupan_meihua extends YFJ_Base_Module {

    public function __construct() {
        $this->module_id = 'liupan_meihua';             // 1. 修改模块 ID
        $this->shortcode = 'yfj_liupan_meihua';         // 2. 修改短代码
        $this->api_endpoint = '/v1/Liupan/meihua';      // 3. 配置对应的真实 API 接口

        parent::__construct();
    }

    /**
     * 专属数据拦截与加工引擎 (重写基类方法)
     * 在这里可以对 API 返回的原始数据进行格式化、过滤或追加二次计算的自定义数据。
     */
    protected function process_api_data($raw_data) {
        // 1. 确保数据是数组格式，防止报错
        if (is_array($raw_data)) {
            //如果 API 没返回格局，给个默认的兜底值
            if (!isset($raw_data['base_info']['zhengge'])) {
                $raw_data['base_info']['zhengge'] = '未入格';
            }
        }

        //将处理后的数据返回给 views/result.php 进行渲染
        return $raw_data;
    }

    /**
     * 沙盒模式下的模拟数据
     */
    protected function get_demo_data($post_data) {
        //获取当前后台设置的语言
        $lang = get_option('yfj_language', 'zh-cn');

        // 1. 把你的完整 JSON 粘贴到单引号里面（要考虑到zh-cn 和 zh-tw）
        $demo_json_zh_cn = '{"errcode":0,"errmsg":"请求成功","notice":"本次测算结果仅供娱乐使用，请勿用于封建迷信和违法用途。","data":{"sex":"女","model":"自动起卦","gongli":"2025-03-15 15:12:00","nongli":"二〇二五年二月十六日 申时","nianming":"乙丑","sizhu_info":{"year_gan":"乙","year_zhi":"巳","month_gan":"己","month_zhi":"卯","day_gan":"癸","day_zhi":"未","hour_gan":"庚","hour_zhi":"申"},"gua_info":{"bengua":{"gua_mark":"111110","gua_name":"泽天夬","gua_qian":"蜘蛛脱网赛天军，粘住游蜂翅翎毛，幸有大风吹破网，脱离灾难又逍遥。","gua_qian_desc":"异卦(下乾上兑)相叠。乾为天为健；兑为泽为悦。泽气上升，决注成雨，雨施大地，滋润万物。五阳去一阴，去之不难，决(去之意)即可，故名为夬(guài)，夬即决。","gua_yaoci":"夬：扬于王庭，孚号，有厉，告自邑，不利即戎，利有攸往。彖曰：夬，决也，刚决柔也。健而说，决而和，扬于王庭，柔乘五刚也。孚号有厉，其危乃光也。告自邑，不利即戎，所尚乃穷也。利有攸往，刚长乃终也。象曰：泽上于天，夬；君子以施禄及下，居德则忌。初九：壮于前趾，往不胜为吝。象曰：不胜而往，咎也。九二：惕号，莫夜有戎，勿恤。象曰：莫夜有戎，得中道也。九三：壮于頄，有凶。君子夬夬，独行遇雨，若濡有愠，无咎。象曰：君子夬夬，终无咎也。九四：臀无肤，其行次且。牵羊悔亡，闻言不信。象曰：其行次且，位不当也。闻言不信，聪不明也。九五：苋陆夬夬，中行无咎。象曰：中行无咎，中未光也。上六：无号，终有凶。象曰：无号之凶，终不可长也。","gua_description":{"gua_shiye":"处在兴盛阶段，但已孕育着普遍的危险。务必施恩泽给他人，勿居功自傲，主动团结他人，不干冒险的事。时时提高警惕，防止小人的破坏。但不可莽撞，应持和缓的手段去决断小人，避免过犹不及。","gua_jingshang":"市场正在走向衰落的状态，不宜大量活动，随时注意转向。开拓新领域时，加强同他人的合作。但务必充分注意别有用心的奸诈小人趁机捣乱和破坏。","gua_qiuming":"虚心求教，充实自身实力。但应量力而行，不可盲目自大。更不可同小人合流，徒虚名而败坏事业。","gua_waichu":"不宜过于频繁，以逸待劳最佳。外出旅行吉利。","gua_hunlian":"防止上介绍人的当，也应注意对方的目的。","gua_juece":"性格矛盾，往往表面刚强而内心虚弱，在关键的时刻，败坏事业。虚心听取他人劝告，切勿鲁莽，多谋深思，用柔和的态度待人处世。"},"gua_xiongji":"上上卦"},"hugua":{"gua_mark":"111111","gua_name":"乾为天","gua_qian":"困龙得水好运交，不由喜气上眉梢，一切谋望皆如意，向后时运渐渐高。","gua_qian_desc":"同卦(下乾上乾)相叠。象征天，喻龙(德才的君子)，又象征纯粹的阳和健，表明兴盛强健。乾卦是根据万物变通的道理，以“元、亨、利、贞”为卦辞，示吉祥如意，教导人遵守天道的德行。","gua_yaoci":"乾：元，亨，利，贞。初九：潜龙，勿用。九二：见龙再田，利见大人。九三：君子终日乾乾，夕惕若，厉无咎。九四：或跃在渊，无咎。九五：飞龙在天，利见大人。上九：亢龙有悔。用九：见群龙无首，吉。","gua_description":{"gua_shiye":"大吉大利，万事如意，心想事成，自有天佑，春风得意，事业如日中天。但阳气已达顶点，盛极必衰，务须提高警惕，小心谨慎。力戒骄傲，冷静处世，心境平和，如是则能充分发挥才智，保证事业成功。","gua_jingshang":"十分顺利，有发展向上的大好机会。但切勿操之过急，宜冷静分析形势，把握时机，坚持商业道德，冷静对待中途出现的困难，定会有满意的结果。","gua_qiuming":"潜在能力尚未充分发挥，只要进一步努力，克服骄傲自满情绪，进业修德，以渊博学识和高尚品质，成君子之名。","gua_waichu":"利于出行，结伴而行更佳。","gua_hunlian":"阳盛阴衰，但刚柔可相济，形成美满结果。女性温柔者更佳。","gua_juece":"可成就大的事业。坚持此卦的刚健、正直、公允的实质，修养德行，积累知识，坚定信念，自强不息，必能克服困难，消除灾难。"},"gua_xiongji":"上上卦"},"biangua":{"gua_mark":"011110","gua_name":"泽风大过","gua_qian":"夜晚梦里梦金银，醒来仍不见一文，目下只宜求本分，思想络是空劳神。","gua_qian_desc":"异卦(下巽上兑)相叠。兑为泽、为悦，巽为木、为顺，泽水淹舟，遂成大错。阴阳爻相反，阳大阴小，行动非常，有过度形象，内刚外柔。","gua_yaoci":"大过：栋桡，利有攸往，亨。彖曰：大过，大者过也。栋桡，本末弱也。刚过而中，巽而说行，利有攸往，乃亨。大过之时义大矣哉！象曰：泽灭木，大过；君子以独立不惧，遁世无闷。初六：藉用白茅，无咎。象曰：藉用白茅，柔在下也。九二：枯杨生秭，老夫得其女妻，无不利。象曰：老夫女妻，过以相与也。九三：栋桡，凶。象曰：栋桡之凶，不可以有辅也。九四：栋隆，吉；有它吝。象曰：栋隆之吉，不桡乎下也。九五：枯杨生华，老妇得士夫，无咎无誉。象曰：枯杨生华，何可久也。老妇士夫，亦可丑也。上六：过涉灭顶，凶，无咎。象曰：过涉之凶，不可咎也。","gua_description":{"gua_shiye":"事业出现隐患，甚至危机四伏，务必十分小心谨慎，唯有坚守中道，以谦虚和悦的手段，胆大心细，求助他人相助。必要时可采取非常手段，不拘常规，予以冒险。","gua_jingshang":"操之过急，发展过快，宜收缩调整。竞争处于不利地步，切勿过度自信，更不得刚愎自用，宜随时观测风向，待机行动。在有确切把握之下，不妨冒险，争取时机的好转。","gua_qiuming":"最忌不务实际，追求不切实际的虚名，以致盛名不符。唯以谦逊态度，谨慎行动，潜心努力，不怕世人指现，一往直前，追求最初的目标。","gua_waichu":"行动务必慎重，但不可过于拘泥，必要时不妨采取特殊行动。","gua_hunlian":"自知之明最为重要，不可急于求成，应慎重考虑，并以正当手段，促成事情的成功。但也不排除必要的精明手段。","gua_juece":"处在非常时期，若不能妥善处置，则极为不利，针对实际情况，既不可轻举妄动，也不可优柔寡断，而应刚柔相济，虚心征求他人意见，慎重行动，大胆追求，却又不怕流言，争取时局好转。"},"gua_xiongji":"中下卦"},"cuogua":{"gua_mark":"000001","gua_name":"山地剥","gua_qian":"鹊遇天晚宿林中，不知林内先有鹰，虽然同处心生恶，卦若逢之是非轻。","gua_qian_desc":"异卦(下坤上艮)相叠。五阴在下，一阳在上，阴盛而阳孤；高山附于地。二者都是剥落象，故为“剥卦”。此卦阴盛阳衰，喻小人得势，君子困顿，事业败坏。","gua_yaoci":"剥：不利有攸往。彖曰：剥，剥也，柔变刚也。不利有攸往，小人长也。顺而止之，观象也。君子尚消息盈虚，天行也。象曰：山附地上，剥；上以厚下，安宅。　　初六：剥牀以足，蔑贞凶。象曰：剥牀以足，以灭下也。六二：剥牀以辨，蔑贞凶。象曰：剥牀以辨，未有与也。六三：剥之，无咎。象曰：剥之无咎，失上下也。六四：剥牀以肤，凶。象曰：剥牀以肤，切近灾也。六五：贯鱼，以宫人宠，无不利。象曰：以宫人宠，终无尤也。上九：硕果不食，君子得舆，小人剥庐。象曰：君子得舆，民所载也。小人剥庐，终不可用也。","gua_description":{"gua_shiye":"时运不佳，乃大势所趋，个人只能顺应时势而暂停行动，静观待变，不可冒险，积极创造条件，增强实力，谨慎隐忍，勿与小人同流。时来运转，成就事业，为期不远。","gua_jingshang":"已从高峰转入低落，进入不景气时期，需要认真总结经验教训，进行整顿，尤其不可孤注一掷。景气形势一旦到来，可顺势从容再起。","gua_qiuming":"成功的可能性不大，不宜执意强求，应继续创造条件，努力提高自己，充实处世的本领，增强实力，待机东山再起。","gua_waichu":"暂缓为好。可在充分准备之后动身。","gua_hunlian":"务须慎重考虑，除非有十分般配者，不要随便进行。双方应注意维护家庭的和睦。","gua_juece":"一生曲折较多，往往隐入不顺利的境况，甚至绝境。但可绝处逢生。只要冷静分析形势，顽强拼搏，一定会彻底改变命运，获得美好的结果，为他人惊羡。关键是不可急于求成，尤其不可冒险。须顺应时势，并防小人陷害。"},"gua_xiongji":"中下卦"},"zonggua":{"gua_mark":"011111","gua_name":"天风姤","gua_qian":"他乡遇友喜气欢，须知运气福重添，自今交了顺当运，向后管保不相干。","gua_qian_desc":"异卦(下巽上乾)相叠。乾为天，巽为风。天下有风，吹遍大地，阴阳交合，万物茂盛。姤(gǒu)卦与夬卦相反，互为“综卦”。姤即遘，阴阳相遇。但五阳一阴，不能长久相处。","gua_yaoci":"姤：女壮，勿用取女。彖曰：姤，遇也，柔遇刚也。勿用取女，不可与长也。天地相遇，品物咸章也。刚遇中正，天下大行也。姤之时义大矣哉！象曰：天下有风，姤；后以施命诰四方。初六：系于金柅，贞吉，有攸往，见凶，羸豕踟躅。象曰：系于金柅，柔道牵也。九二：包有鱼，无咎，不利宾。象曰：包有鱼，义不及宾也。九三：臀无肤，其行次且，厉，无大咎。象曰：其行次且，行未牵也。九四：包无鱼，起凶。象曰：无鱼之凶，远民也。九五：以杞包瓜，含章，有陨自天。象曰：九五含章，中正也。有陨自天，志不舍命也。上九：姤其角，吝，无咎。象曰：姤其角，上穷吝也。","gua_description":{"gua_shiye":"合时宜，循时序。但潜在着危机，阴阳不协调。务必依附于强者，多方联系，增强势力，防止小人渔利，争取形势好转。诸事宜及早准备，等待时机，一旦成熟立刻行动。","gua_jingshang":"市场正从红火的状态走向衰危，及早脱身为妙，强行发展有危险。无正直的人相助，却有小人在暗中盘算。对此，务必保持清醒的头脑，寻求可靠的合作伙伴，隐忍待时，以图商业活动的再发展。","gua_qiuming":"性格不很合群，内心自视过高，不免处于困境而不得志。应投靠真诚正直的人，在其支持下成功。","gua_waichu":"有困难，虽无大灾祸，但无人相助。","gua_hunlian":"严格考察对方的道德品质，避免陷入“三角”纠纷。夫妻以诚相待，可转危为安。","gua_juece":"吉利。可在有利的环境中顺利发展，但决不可冒险行事，以免适得其反。其次在于随时提防身边小人的陷害。为此，在邪恶未成势之前即应制止，宁可孤立也不可与小人结伴。"},"gua_xiongji":"上卦"}},"dongyao":"1","has_biangua":"1"}}';
        $demo_json_zh_tw = '{"errcode":0,"errmsg":"請求成功","notice":"本次測算結果僅供娛樂使用，請勿用於封建迷信和違法用途。","data":{"sex":"女","model":"自動起卦","gongli":"2025-03-15 15:12:00","nongli":"二〇二五年二月十六日 申時","nianming":"乙丑","sizhu_info":{"year_gan":"乙","year_zhi":"巳","month_gan":"己","month_zhi":"卯","day_gan":"癸","day_zhi":"未","hour_gan":"庚","hour_zhi":"申"},"gua_info":{"bengua":{"gua_mark":"111110","gua_name":"澤天夬","gua_qian":"蜘蛛脫網賽天軍，粘住遊蜂翅翎毛，幸有大風吹破網，脫離災難又逍遙。","gua_qian_desc":"異卦(下乾上兌)相疊。乾為天為健；兌為澤為悅。澤氣上升，決註成雨，雨施大地，滋潤萬物。五陽去一陰，去之不難，決(去之意)即可，故名為夬(guài)，夬即決。","gua_yaoci":"夬：揚於王庭，孚號，有厲，告自邑，不利即戎，利有攸往。彖曰：夬，決也，剛決柔也。健而說，決而和，揚於王庭，柔乘五剛也。孚號有厲，其危乃光也。告自邑，不利即戎，所尚乃窮也。利有攸往，剛長乃終也。象曰：澤上於天，夬；君子以施祿及下，居德則忌。初九：壯於前趾，往不勝為吝。象曰：不勝而往，咎也。九二：惕號，莫夜有戎，勿恤。象曰：莫夜有戎，得中道也。九三：壯於頄，有兇。君子夬夬，獨行遇雨，若濡有慍，無咎。象曰：君子夬夬，終無咎也。九四：臀無膚，其行次且。牽羊悔亡，聞言不信。象曰：其行次且，位不當也。聞言不信，聰不明也。九五：莧陸夬夬，中行無咎。象曰：中行無咎，中未光也。上六：無號，終有兇。象曰：無號之兇，終不可長也。","gua_description":{"gua_shiye":"處在興盛階段，但已孕育著普遍的危險。務必施恩澤給他人，勿居功自傲，主動團結他人，不幹冒險的事。時時提高警惕，防止小人的破壞。但不可莽撞，應持和緩的手段去決斷小人，避免過猶不及。","gua_jingshang":"市場正在走向衰落的狀態，不宜大量活動，隨時註意轉向。開拓新領域時，加強同他人的合作。但務必充分註意別有用心的奸詐小人趁機搗亂和破壞。","gua_qiuming":"虛心求教，充實自身實力。但應量力而行，不可盲目自大。更不可同小人合流，徒虛名而敗壞事業。","gua_waichu":"不宜過於頻繁，以逸待勞最佳。外出旅行吉利。","gua_hunlian":"防止上介紹人的當，也應註意對方的目的。","gua_juece":"性格矛盾，往往表面剛強而內心虛弱，在關鍵的時刻，敗壞事業。虛心聽取他人勸告，切勿魯莽，多謀深思，用柔和的態度待人處世。"},"gua_xiongji":"上上卦"},"hugua":{"gua_mark":"111111","gua_name":"乾為天","gua_qian":"困龍得水好運交，不由喜氣上眉梢，一切謀望皆如意，向後時運漸漸高。","gua_qian_desc":"同卦(下乾上乾)相疊。象征天，喻龍(德才的君子)，又象征純粹的陽和健，表明興盛強健。乾卦是根據萬物變通的道理，以「元、亨、利、貞」為卦辭，示吉祥如意，教導人遵守天道的德行。","gua_yaoci":"乾：元，亨，利，貞。初九：潛龍，勿用。九二：見龍再田，利見大人。九三：君子終日乾乾，夕惕若，厲無咎。九四：或躍在淵，無咎。九五：飛龍在天，利見大人。上九：亢龍有悔。用九：見群龍無首，吉。","gua_description":{"gua_shiye":"大吉大利，萬事如意，心想事成，自有天佑，春風得意，事業如日中天。但陽氣已達頂點，盛極必衰，務須提高警惕，小心謹慎。力戒驕傲，冷靜處世，心境平和，如是則能充分發揮才智，保證事業成功。","gua_jingshang":"十分順利，有發展向上的大好機會。但切勿操之過急，宜冷靜分析形勢，把握時機，堅持商業道德，冷靜對待中途出現的困難，定會有滿意的結果。","gua_qiuming":"潛在能力尚未充分發揮，只要進一步努力，克服驕傲自滿情緒，進業修德，以淵博學識和高尚品質，成君子之名。","gua_waichu":"利於出行，結伴而行更佳。","gua_hunlian":"陽盛陰衰，但剛柔可相濟，形成美滿結果。女性溫柔者更佳。","gua_juece":"可成就大的事業。堅持此卦的剛健、正直、公允的實質，修養德行，積累知識，堅定信念，自強不息，必能克服困難，消除災難。"},"gua_xiongji":"上上卦"},"biangua":{"gua_mark":"011110","gua_name":"澤風大過","gua_qian":"夜晚夢裏夢金銀，醒來仍不見一文，目下只宜求本分，思想絡是空勞神。","gua_qian_desc":"異卦(下巽上兌)相疊。兌為澤、為悅，巽為木、為順，澤水淹舟，遂成大錯。陰陽爻相反，陽大陰小，行動非常，有過度形象，內剛外柔。","gua_yaoci":"大過：棟橈，利有攸往，亨。彖曰：大過，大者過也。棟橈，本末弱也。剛過而中，巽而說行，利有攸往，乃亨。大過之時義大矣哉！象曰：澤滅木，大過；君子以獨立不懼，遁世無悶。初六：藉用白茅，無咎。象曰：藉用白茅，柔在下也。九二：枯楊生秭，老夫得其女妻，無不利。象曰：老夫女妻，過以相與也。九三：棟橈，兇。象曰：棟橈之兇，不可以有輔也。九四：棟隆，吉；有它吝。象曰：棟隆之吉，不橈乎下也。九五：枯楊生華，老婦得士夫，無咎無譽。象曰：枯楊生華，何可久也。老婦士夫，亦可醜也。上六：過涉滅頂，兇，無咎。象曰：過涉之兇，不可咎也。","gua_description":{"gua_shiye":"事業出現隱患，甚至危機四伏，務必十分小心謹慎，唯有堅守中道，以謙虛和悅的手段，膽大心細，求助他人相助。必要時可采取非常手段，不拘常規，予以冒險。","gua_jingshang":"操之過急，發展過快，宜收縮調整。競爭處於不利地步，切勿過度自信，更不得剛愎自用，宜隨時觀測風向，待機行動。在有確切把握之下，不妨冒險，爭取時機的好轉。","gua_qiuming":"最忌不務實際，追求不切實際的虛名，以致盛名不符。唯以謙遜態度，謹慎行動，潛心努力，不怕世人指現，一往直前，追求最初的目標。","gua_waichu":"行動務必慎重，但不可過於拘泥，必要時不妨采取特殊行動。","gua_hunlian":"自知之明最為重要，不可急於求成，應慎重考慮，並以正當手段，促成事情的成功。但也不排除必要的精明手段。","gua_juece":"處在非常時期，若不能妥善處置，則極為不利，針對實際情況，既不可輕舉妄動，也不可優柔寡斷，而應剛柔相濟，虛心征求他人意見，慎重行動，大膽追求，卻又不怕流言，爭取時局好轉。"},"gua_xiongji":"中下卦"},"cuogua":{"gua_mark":"000001","gua_name":"山地剝","gua_qian":"鵲遇天晚宿林中，不知林內先有鷹，雖然同處心生惡，卦若逢之是非輕。","gua_qian_desc":"異卦(下坤上艮)相疊。五陰在下，一陽在上，陰盛而陽孤；高山附於地。二者都是剝落象，故為「剝卦」。此卦陰盛陽衰，喻小人得勢，君子困頓，事業敗壞。","gua_yaoci":"剝：不利有攸往。彖曰：剝，剝也，柔變剛也。不利有攸往，小人長也。順而止之，觀象也。君子尚消息盈虛，天行也。象曰：山附地上，剝；上以厚下，安宅。　　初六：剝牀以足，蔑貞兇。象曰：剝牀以足，以滅下也。六二：剝牀以辨，蔑貞兇。象曰：剝牀以辨，未有與也。六三：剝之，無咎。象曰：剝之無咎，失上下也。六四：剝牀以膚，兇。象曰：剝牀以膚，切近災也。六五：貫魚，以宮人寵，無不利。象曰：以宮人寵，終無尤也。上九：碩果不食，君子得輿，小人剝廬。象曰：君子得輿，民所載也。小人剝廬，終不可用也。","gua_description":{"gua_shiye":"時運不佳，乃大勢所趨，個人只能順應時勢而暫停行動，靜觀待變，不可冒險，積極創造條件，增強實力，謹慎隱忍，勿與小人同流。時來運轉，成就事業，為期不遠。","gua_jingshang":"已從高峰轉入低落，進入不景氣時期，需要認真總結經驗教訓，進行整頓，尤其不可孤註一擲。景氣形勢一旦到來，可順勢從容再起。","gua_qiuming":"成功的可能性不大，不宜執意強求，應繼續創造條件，努力提高自己，充實處世的本領，增強實力，待機東山再起。","gua_waichu":"暫緩為好。可在充分準備之後動身。","gua_hunlian":"務須慎重考慮，除非有十分般配者，不要隨便進行。雙方應註意維護家庭的和睦。","gua_juece":"一生曲折較多，往往隱入不順利的境況，甚至絕境。但可絕處逢生。只要冷靜分析形勢，頑強拼搏，一定會徹底改變命運，獲得美好的結果，為他人驚羨。關鍵是不可急於求成，尤其不可冒險。須順應時勢，並防小人陷害。"},"gua_xiongji":"中下卦"},"zonggua":{"gua_mark":"011111","gua_name":"天風姤","gua_qian":"他鄉遇友喜氣歡，須知運氣福重添，自今交了順當運，向後管保不相幹。","gua_qian_desc":"異卦(下巽上乾)相疊。乾為天，巽為風。天下有風，吹遍大地，陰陽交合，萬物茂盛。姤(gǒu)卦與夬卦相反，互為「綜卦」。姤即遘，陰陽相遇。但五陽一陰，不能長久相處。","gua_yaoci":"姤：女壯，勿用取女。彖曰：姤，遇也，柔遇剛也。勿用取女，不可與長也。天地相遇，品物鹹章也。剛遇中正，天下大行也。姤之時義大矣哉！象曰：天下有風，姤；後以施命誥四方。初六：系於金柅，貞吉，有攸往，見兇，羸豕踟躅。象曰：系於金柅，柔道牽也。九二：包有魚，無咎，不利賓。象曰：包有魚，義不及賓也。九三：臀無膚，其行次且，厲，無大咎。象曰：其行次且，行未牽也。九四：包無魚，起兇。象曰：無魚之兇，遠民也。九五：以杞包瓜，含章，有隕自天。象曰：九五含章，中正也。有隕自天，誌不舍命也。上九：姤其角，吝，無咎。象曰：姤其角，上窮吝也。","gua_description":{"gua_shiye":"合時宜，循時序。但潛在著危機，陰陽不協調。務必依附於強者，多方聯系，增強勢力，防止小人漁利，爭取形勢好轉。諸事宜及早準備，等待時機，一旦成熟立刻行動。","gua_jingshang":"市場正從紅火的狀態走向衰危，及早脫身為妙，強行發展有危險。無正直的人相助，卻有小人在暗中盤算。對此，務必保持清醒的頭腦，尋求可靠的合作夥伴，隱忍待時，以圖商業活動的再發展。","gua_qiuming":"性格不很合群，內心自視過高，不免處於困境而不得誌。應投靠真誠正直的人，在其支持下成功。","gua_waichu":"有困難，雖無大災禍，但無人相助。","gua_hunlian":"嚴格考察對方的道德品質，避免陷入「三角」糾紛。夫妻以誠相待，可轉危為安。","gua_juece":"吉利。可在有利的環境中順利發展，但決不可冒險行事，以免適得其反。其次在於隨時提防身邊小人的陷害。為此，在邪惡未成勢之前即應製止，寧可孤立也不可與小人結伴。"},"gua_xiongji":"上卦"}},"dongyao":"1","has_biangua":"1"}}';

        if ($lang == 'zh-tw') {
            $demo_json = $demo_json_zh_tw;
